mapper.select:
SELECT 'N' AS FLAG , DONG , SIL , SIL2 , NUM , USINGYN , LAYER , HAKBUN , '' AS DAEHAK , '' AS HAKGWAFNM , '' AS HAKYEON , '' AS IRUM , '' AS SEX , '' AS CHK FROM EAGLE.DORMROOM WHERE 1=1 AND USINGYN = 'N'
AND DONG = #{dong}
AND YEONDO = #{yeondo} AND HAKGI = #{hakgi}
ORDER BY SIL , SIL2 , NUM

mapper.update:
     BEGIN	


	    UPDATE EAGLE.DORMROOM
		   SET USINGYN = 'N'			   
		 WHERE HAKBUN  = #{hakbun};


		UPDATE EAGLE.DORMROOM
		   SET USINGYN = 'Y'
		     , HAKBUN  = #{hakbun}
		     , USEDATE = SYSDATE			   
		 WHERE DONG    = #{dong}
		   AND SIL     = #{sil}

		   AND SIL2    = #{sil2}

		   AND NUM     = #{num};


		UPDATE EAGLE.DOMASTER
		   SET DONG    = #{dong}
		     , SIL     = #{sil}

		     , SIL2    = #{sil2} 

		 WHERE YEONDO||HAKGI IN(SELECT YEAR||HAKGI FROM EAGLE.COM_YEAR WHERE BUSS_GRP_CD = '00203006' AND BUSS_FG = 'DORM_20' AND USE_YN = 'Y')
		   AND HAKBUN  = #{hakbun};

	 END ;
